def minJump(n, d, s):
    if s[-1] == '0':
        return -1
    dp = [float('inf')] * (n + 1)
    dp[0] = -1
    dp[1] = 0
    for i in range(1, n + 1):
        for j in range(1, d + 1):
            if i - j >= 0 and s[i - j] == '1':
                dp[i] = min(dp[i], dp[i - j] + 1)
    return dp[n] if dp[n] != float('inf') else -1


n, d = map(int, input().split())
